class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int satisfied = 0;
        int currentGrumpy = 0;
        int maxSatisfied = 0;
        for (int i = 0; i < customers.length; i++) {
            if (grumpy[i] == 1) {
                currentGrumpy++;
            }
            satisfied += customers[i] - (grumpy[i] == 1 ? 0 : customers[i]);
            if (i >= minutes) {
                if (grumpy[i - minutes] == 1) {
                    currentGrumpy--;
                }
                satisfied -= customers[i - minutes] - (grumpy[i - minutes] == 1 ? 0 : customers[i - minutes]);
            }
            maxSatisfied = Math.max(maxSatisfied, satisfied);
        }
        return maxSatisfied;
    }
}
